import React, { useEffect, useState } from 'react';
import './AccountSettings.css';

const AccountSettings = () => {
  const [user, setUser] = useState({ name: '', role: '', email: '' });

  useEffect(() => {
    const fetchUserByEmail = async () => {
      const userEmail = localStorage.getItem('userEmail'); // Récupérer l'email stocké

      if (!userEmail) {
        console.error("Aucun email trouvé dans localStorage.");
        return;
      }

      try {
        const response = await fetch(`http://localhost:5001/user/email/${userEmail}`);
        const data = await response.json();

        if (response.ok) {
          setUser(data);
        } else {
          console.error("Erreur lors de la récupération des données:", data.message);
        }
      } catch (error) {
        console.error("Erreur de connexion à l'API:", error);
      }
    };

    fetchUserByEmail();
  }, []);

  return (
    <div className='accountsettings'>
      <h1 className='mainhead1'>Personal Information</h1>

      <div className='form'>
        <div className='form-group'>
          <label htmlFor='name'>Your Name <span>*</span></label>
          <input type='text' name='name' id='name' value={user.name} readOnly />
        </div>

        <div className='form-group'>
          <label htmlFor='role'>Role <span>*</span></label>
          <input type='text' name='role' id='role' value={user.role} readOnly />
        </div>

        <div className='form-group'>
          <label htmlFor='email'>Email <span>*</span></label>
          <input type='email' name='email' id='email' value={user.email} readOnly />
        </div>
      </div>

      <button className='mainbutton1'>Save Changes</button>
    </div>
  );
};

export default AccountSettings;
